  1вҶ’import type { SubmissionInput } from '../../shared/types';
  2вҶ’
  3вҶ’const DB_NAME = 'adl_offline_queue';
  4вҶ’const STORE_NAME = 'submission_queue';
  5вҶ’const SYNC_ERROR_STORE_NAME = 'submission_sync_errors';
  6вҶ’const DB_VERSION = 2;
  7вҶ’
  8вҶ’export type QueueStatus = 'pending' | 'syncing' | 'failed' | 'synced';
  9вҶ’
 10вҶ’export interface QueueItem {
 11вҶ’  id: string;
 12вҶ’  idempotencyKey: string;
 13вҶ’  payload: SubmissionInput;
 14вҶ’  status: QueueStatus;
 15вҶ’  attempts: number;
 16вҶ’  retryCount: number;
 17вҶ’  nextRetryAt?: string;
 18вҶ’  lastError?: string;
 19вҶ’  createdAt: string;
 20вҶ’  updatedAt: string;
 21вҶ’}
 22вҶ’
 23вҶ’export interface SyncErrorRecord {
 24вҶ’  id: string;
 25вҶ’  queueItemId: string;
 26вҶ’  message: string;
 27вҶ’  createdAt: string;
 28вҶ’  payloadSummary: {
 29вҶ’    eventType: SubmissionInput['eventType'];
 30вҶ’    category: SubmissionInput['category'];
 31вҶ’    pointId?: string;
 32вҶ’    location?: SubmissionInput['location'];
 33вҶ’  };
 34вҶ’}
 35вҶ’
 36вҶ’export interface QueueSyncSummary {
 37вҶ’  synced: number;
 38вҶ’  failed: number;
 39вҶ’  syncedIds: string[];
 40вҶ’  failedIds: string[];
 41вҶ’  permanentFailures: number;
 42вҶ’  permanentFailureIds: string[];
 43вҶ’  permanentFailureMessages: string[];
 44вҶ’  remaining: number;
 45вҶ’}
 46вҶ’
 47вҶ’function toQueueErrorInfo(error: unknown): { message: string; retryable: boolean } {
 48вҶ’  const fallback = 'Unable to sync queued submission';
 49вҶ’  if (error instanceof Error) {
 50вҶ’    const withRetryable = error as Error & { retryable?: unknown };
 51вҶ’    const retryable = typeof withRetryable.retryable === 'boolean' ? withRetryable.retryable : true;
 52вҶ’    const message = error.message?.trim() || fallback;
 53вҶ’    return { message, retryable };
 54вҶ’  }
 55вҶ’  return { message: String(error ?? fallback), retryable: true };
 56вҶ’}
 57вҶ’
 58вҶ’function ensureIndexedDb(): IDBFactory {
 59вҶ’  if (typeof indexedDB === 'undefined') {
 60вҶ’    throw new Error('IndexedDB is not available');
 61вҶ’  }
 62вҶ’  return indexedDB;
 63вҶ’}
 64вҶ’
 65вҶ’function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
 66вҶ’  return new Promise((resolve, reject) => {
 67вҶ’    request.onsuccess = () => resolve(request.result);
 68вҶ’    request.onerror = () => reject(request.error);
 69вҶ’  });
 70вҶ’}
 71вҶ’
 72вҶ’function transactionDone(tx: IDBTransaction): Promise<void> {
 73вҶ’  return new Promise((resolve, reject) => {
 74вҶ’    tx.oncomplete = () => resolve();
 75вҶ’    tx.onerror = () => reject(tx.error);
 76вҶ’    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
 77вҶ’  });
 78вҶ’}
 79вҶ’
 80вҶ’async function openDb(): Promise<IDBDatabase> {
 81вҶ’  const db = ensureIndexedDb();
 82вҶ’  return await new Promise<IDBDatabase>((resolve, reject) => {
 83вҶ’    const request = db.open(DB_NAME, DB_VERSION);
 84вҶ’    request.onupgradeneeded = () => {
 85вҶ’      const nextDb = request.result;
 86вҶ’      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
 87вҶ’        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
 88вҶ’      }
 89вҶ’      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
 90вҶ’        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
 91вҶ’      }
 92вҶ’    };
 93вҶ’    request.onsuccess = () => resolve(request.result);
 94вҶ’    request.onerror = () => reject(request.error);
 95вҶ’  });
 96вҶ’}
 97вҶ’
 98вҶ’async function putItem(item: QueueItem): Promise<void> {
 99вҶ’  const db = await openDb();
100вҶ’  const tx = db.transaction(STORE_NAME, 'readwrite');
101вҶ’  tx.objectStore(STORE_NAME).put(item);
102вҶ’  await transactionDone(tx);
103вҶ’  db.close();
104вҶ’}
105вҶ’
106вҶ’export async function enqueueSubmission(payload: SubmissionInput): Promise<QueueItem> {
107вҶ’  const now = new Date().toISOString();
108вҶ’  const item: QueueItem = {
109вҶ’    id: crypto.randomUUID(),
110вҶ’    idempotencyKey: crypto.randomUUID(),
111вҶ’    payload,
112вҶ’    status: 'pending',
113вҶ’    attempts: 0,
114вҶ’    retryCount: 0,
115вҶ’    createdAt: now,
116вҶ’    updatedAt: now
117вҶ’  };
118вҶ’  await putItem(item);
119вҶ’  return item;
120вҶ’}
121вҶ’
122вҶ’export async function listQueueItems(): Promise<QueueItem[]> {
123вҶ’  const db = await openDb();
124вҶ’  const tx = db.transaction(STORE_NAME, 'readonly');
125вҶ’  const request = tx.objectStore(STORE_NAME).getAll();
126вҶ’  const result = await requestToPromise(request);
127вҶ’  await transactionDone(tx);
128вҶ’  db.close();
129вҶ’  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
130вҶ’}
131вҶ’
132вҶ’async function updateItem(id: string, updater: (item: QueueItem) => QueueItem): Promise<QueueItem | null> {
133вҶ’  const db = await openDb();
134вҶ’  return await new Promise<QueueItem | null>((resolve, reject) => {
135вҶ’    const tx = db.transaction(STORE_NAME, 'readwrite');
136вҶ’    const store = tx.objectStore(STORE_NAME);
137вҶ’    let updated: QueueItem | null = null;
138вҶ’    const getRequest = store.get(id);
139вҶ’    getRequest.onsuccess = () => {
140вҶ’      const existing = getRequest.result as QueueItem | undefined;
141вҶ’      if (!existing) return;
142вҶ’      updated = updater(existing);
143вҶ’      store.put(updated);
144вҶ’    };
145вҶ’    getRequest.onerror = () => reject(getRequest.error);
146вҶ’    tx.oncomplete = () => {
147вҶ’      db.close();
148вҶ’      resolve(updated);
149вҶ’    };
150вҶ’    tx.onerror = () => {
151вҶ’      db.close();
152вҶ’      reject(tx.error);
153вҶ’    };
154вҶ’    tx.onabort = () => {
155вҶ’      db.close();
156вҶ’      reject(tx.error ?? new Error('IndexedDB transaction aborted'));
157вҶ’    };
158вҶ’  });
159вҶ’}
160вҶ’
161вҶ’async function removeItem(id: string): Promise<void> {
162вҶ’  const db = await openDb();
163вҶ’  const tx = db.transaction(STORE_NAME, 'readwrite');
164вҶ’  tx.objectStore(STORE_NAME).delete(id);
165вҶ’  await transactionDone(tx);
166вҶ’  db.close();
167вҶ’}
168вҶ’
169вҶ’async function putSyncErrorRecord(record: SyncErrorRecord): Promise<void> {
170вҶ’  const db = await openDb();
171вҶ’  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
172вҶ’  tx.objectStore(SYNC_ERROR_STORE_NAME).put(record);
173вҶ’  await transactionDone(tx);
174вҶ’  db.close();
175вҶ’}
176вҶ’
177вҶ’export async function listSyncErrorRecords(): Promise<SyncErrorRecord[]> {
178вҶ’  const db = await openDb();
179вҶ’  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readonly');
180вҶ’  const request = tx.objectStore(SYNC_ERROR_STORE_NAME).getAll();
181вҶ’  const result = await requestToPromise(request);
182вҶ’  await transactionDone(tx);
183вҶ’  db.close();
184вҶ’  return (result as SyncErrorRecord[]).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
185вҶ’}
186вҶ’
187вҶ’export async function clearSyncErrorRecords(): Promise<void> {
188вҶ’  const db = await openDb();
189вҶ’  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
190вҶ’  tx.objectStore(SYNC_ERROR_STORE_NAME).clear();
191вҶ’  await transactionDone(tx);
192вҶ’  db.close();
193вҶ’}
194вҶ’
195вҶ’export async function getQueueStats(): Promise<{ pending: number; failed: number; total: number }> {
196вҶ’  const items = await listQueueItems();
197вҶ’  return {
198вҶ’    pending: items.filter((item) => item.status === 'pending' || item.status === 'syncing').length,
199вҶ’    failed: items.filter((item) => item.status === 'failed').length,
200вҶ’    total: items.length
201вҶ’  };
202вҶ’}
203вҶ’
204вҶ’export async function flushOfflineQueue(
205вҶ’  sendFn: (payload: SubmissionInput, options?: { idempotencyKey?: string }) => Promise<void>,
206вҶ’): Promise<QueueSyncSummary> {
207вҶ’  const items = await listQueueItems();
208вҶ’  const now = Date.now();
209вҶ’  let synced = 0;
210вҶ’  let failed = 0;
211вҶ’  const syncedIds: string[] = [];
212вҶ’  const failedIds: string[] = [];
213вҶ’  let permanentFailures = 0;
214вҶ’  const permanentFailureIds: string[] = [];
215вҶ’  const permanentFailureMessages = new Set<string>();
216вҶ’
217вҶ’  for (const item of items) {
218вҶ’    // Skip items not yet ready for retry (exponential backoff).
219вҶ’    if (item.nextRetryAt && new Date(item.nextRetryAt).getTime() > now) {
220вҶ’      failed += 1;
221вҶ’      failedIds.push(item.id);
222вҶ’      continue;
223вҶ’    }
224вҶ’
225вҶ’    await updateItem(item.id, (current) => ({
226вҶ’      ...current,
227вҶ’      status: 'syncing',
228вҶ’      attempts: current.attempts + 1,
229вҶ’      updatedAt: new Date().toISOString()
230вҶ’    }));
231вҶ’
232вҶ’    try {
233вҶ’      await sendFn(item.payload, { idempotencyKey: item.idempotencyKey });
234вҶ’      await removeItem(item.id);
235вҶ’      synced += 1;
236вҶ’      syncedIds.push(item.id);
237вҶ’    } catch (error) {
238вҶ’      const details = toQueueErrorInfo(error);
239вҶ’      if (details.retryable) {
240вҶ’        failed += 1;
241вҶ’        failedIds.push(item.id);
242вҶ’        const retryCount = (item.retryCount ?? 0) + 1;
243вҶ’        const baseDelay = Math.min(30000, 1000 * Math.pow(2, retryCount));
244вҶ’        const jitter = Math.random() * 1000;
245вҶ’        const nextRetryAt = new Date(now + baseDelay + jitter).toISOString();
246вҶ’        await updateItem(item.id, (current) => ({
247вҶ’          ...current,
248вҶ’          status: 'failed',
249вҶ’          retryCount,
250вҶ’          nextRetryAt,
251вҶ’          updatedAt: new Date().toISOString(),
252вҶ’          lastError: details.message,
253вҶ’        }));
254вҶ’        continue;
255вҶ’      }
256вҶ’
257вҶ’      permanentFailures += 1;
258вҶ’      permanentFailureIds.push(item.id);
259вҶ’      permanentFailureMessages.add(details.message);
260вҶ’      await putSyncErrorRecord({
261вҶ’        id: crypto.randomUUID(),
262вҶ’        queueItemId: item.id,
263вҶ’        message: details.message,
264вҶ’        createdAt: new Date().toISOString(),
265вҶ’        payloadSummary: {
266вҶ’          eventType: item.payload.eventType,
267вҶ’          category: item.payload.category,
268вҶ’          pointId: item.payload.pointId,
269вҶ’          location: item.payload.location,
270вҶ’        },
271вҶ’      });
272вҶ’      await removeItem(item.id);
273вҶ’    }
274вҶ’  }
275вҶ’
276вҶ’  const remaining = (await listQueueItems()).length;
277вҶ’  return {
278вҶ’    synced,
279вҶ’    failed,
280вҶ’    syncedIds,
281вҶ’    failedIds,
282вҶ’    permanentFailures,
283вҶ’    permanentFailureIds,
284вҶ’    permanentFailureMessages: Array.from(permanentFailureMessages),
285вҶ’    remaining,
286вҶ’  };
287вҶ’}
