  1вҶ’import { apiFetch } from './api';
  2вҶ’import type { SubmissionInput } from '../../shared/types';
  3вҶ’import { getClientDeviceInfo } from './deviceProfile';
  4вҶ’import { sanitizeErrorMessage as sanitizeBase } from './errorUtils';
  5вҶ’
  6вҶ’const DEFAULT_SYNC_ERROR = 'Unable to sync submission right now.';
  7вҶ’
  8вҶ’function sanitizeErrorMessage(input: unknown, fallback = DEFAULT_SYNC_ERROR): string {
  9вҶ’  const result = sanitizeBase(input, fallback);
 10вҶ’  return result === fallback ? fallback : result.replace(/^Error:\s*/i, '');
 11вҶ’}
 12вҶ’
 13вҶ’async function extractResponseMessage(response: Response): Promise<string> {
 14вҶ’  const fallback = response.statusText || DEFAULT_SYNC_ERROR;
 15вҶ’  const contentType = response.headers.get('content-type')?.toLowerCase() ?? '';
 16вҶ’
 17вҶ’  if (contentType.includes('application/json')) {
 18вҶ’    try {
 19вҶ’      const payload = (await response.json()) as { error?: unknown; message?: unknown };
 20вҶ’      return sanitizeErrorMessage(payload?.error ?? payload?.message, fallback);
 21вҶ’    } catch {
 22вҶ’      return fallback;
 23вҶ’    }
 24вҶ’  }
 25вҶ’
 26вҶ’  try {
 27вҶ’    const text = await response.text();
 28вҶ’    return sanitizeErrorMessage(text, fallback);
 29вҶ’  } catch {
 30вҶ’    return fallback;
 31вҶ’  }
 32вҶ’}
 33вҶ’
 34вҶ’function isRetryableStatus(status: number): boolean {
 35вҶ’  if (status === 408 || status === 425 || status === 429) return true;
 36вҶ’  return status >= 500;
 37вҶ’}
 38вҶ’
 39вҶ’export class SubmissionSyncError extends Error {
 40вҶ’  retryable: boolean;
 41вҶ’  status: number | null;
 42вҶ’
 43вҶ’  constructor(
 44вҶ’    message: string,
 45вҶ’    options: {
 46вҶ’      retryable?: boolean;
 47вҶ’      status?: number | null;
 48вҶ’      cause?: unknown;
 49вҶ’    } = {},
 50вҶ’  ) {
 51вҶ’    super(message);
 52вҶ’    this.name = 'SubmissionSyncError';
 53вҶ’    this.retryable = Boolean(options.retryable);
 54вҶ’    this.status = options.status ?? null;
 55вҶ’    if (options.cause !== undefined) {
 56вҶ’      (this as Error & { cause?: unknown }).cause = options.cause;
 57вҶ’    }
 58вҶ’  }
 59вҶ’}
 60вҶ’
 61вҶ’export function toSubmissionSyncError(error: unknown): SubmissionSyncError {
 62вҶ’  if (error instanceof SubmissionSyncError) return error;
 63вҶ’  if (error instanceof Error) {
 64вҶ’    return new SubmissionSyncError(sanitizeErrorMessage(error.message), { retryable: true, cause: error });
 65вҶ’  }
 66вҶ’  return new SubmissionSyncError(DEFAULT_SYNC_ERROR, { retryable: true, cause: error });
 67вҶ’}
 68вҶ’
 69вҶ’function withClientDevice(payload: SubmissionInput): SubmissionInput {
 70вҶ’  const details =
 71вҶ’    payload.details && typeof payload.details === 'object'
 72вҶ’      ? { ...(payload.details as Record<string, unknown>) }
 73вҶ’      : {};
 74вҶ’  if (!details.clientDevice) {
 75вҶ’    details.clientDevice = getClientDeviceInfo();
 76вҶ’  }
 77вҶ’  return { ...payload, details };
 78вҶ’}
 79вҶ’
 80вҶ’export async function sendSubmissionPayload(payload: SubmissionInput, options?: { idempotencyKey?: string }): Promise<void> {
 81вҶ’  const enrichedPayload = withClientDevice(payload);
 82вҶ’  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
 83вҶ’  if (options?.idempotencyKey) {
 84вҶ’    headers['X-Idempotency-Key'] = options.idempotencyKey;
 85вҶ’  }
 86вҶ’  let response: Response;
 87вҶ’  try {
 88вҶ’    response = await apiFetch('/api/submissions', {
 89вҶ’      method: 'POST',
 90вҶ’      headers,
 91вҶ’      body: JSON.stringify(enrichedPayload),
 92вҶ’    });
 93вҶ’  } catch (error) {
 94вҶ’    throw new SubmissionSyncError(DEFAULT_SYNC_ERROR, { retryable: true, cause: error });
 95вҶ’  }
 96вҶ’
 97вҶ’  if (response.ok) return;
 98вҶ’
 99вҶ’  const message = await extractResponseMessage(response);
100вҶ’  throw new SubmissionSyncError(message, {
101вҶ’    retryable: isRetryableStatus(response.status),
102вҶ’    status: response.status,
103вҶ’  });
104вҶ’}
105вҶ’

  1вҶ’import { Pool, type PoolConfig, type QueryResult } from "pg";
  2вҶ’
  3вҶ’const NETWORK_ERROR_CODES = new Set([
  4вҶ’  "ECONNREFUSED",
  5вҶ’  "ECONNRESET",
  6вҶ’  "EHOSTUNREACH",
  7вҶ’  "ENETUNREACH",
  8вҶ’  "ENOTFOUND",
  9вҶ’  "ETIMEDOUT",
 10вҶ’  "SELF_SIGNED_CERT_IN_CHAIN",
 11вҶ’  "DEPTH_ZERO_SELF_SIGNED_CERT",
 12вҶ’  "UNABLE_TO_VERIFY_LEAF_SIGNATURE",
 13вҶ’  "53300",
 14вҶ’  "57P01",
 15вҶ’  "08001",
 16вҶ’  "08006",
 17вҶ’]);
 18вҶ’
 19вҶ’const DEFAULT_QUERY_TIMEOUT_MS = Number(process.env.POSTGRES_QUERY_TIMEOUT_MS ?? "10000") || 10000;
 20вҶ’
 21вҶ’let pool: Pool | null = null;
 22вҶ’
 23вҶ’export class StorageUnavailableError extends Error {
 24вҶ’  readonly code = "storage_unavailable";
 25вҶ’
 26вҶ’  constructor(message: string, options: { cause?: unknown } = {}) {
 27вҶ’    super(message);
 28вҶ’    this.name = "StorageUnavailableError";
 29вҶ’    if (options.cause !== undefined) {
 30вҶ’      (this as Error & { cause?: unknown }).cause = options.cause;
 31вҶ’    }
 32вҶ’  }
 33вҶ’}
 34вҶ’
 35вҶ’export function isStorageUnavailableError(error: unknown): error is StorageUnavailableError {
 36вҶ’  return error instanceof StorageUnavailableError;
 37вҶ’}
 38вҶ’
 39вҶ’function resolveConnectionString(): string | null {
 40вҶ’  return (
 41вҶ’    process.env.ADL_POSTGRES_URL ??
 42вҶ’    process.env.POSTGRES_URL ??
 43вҶ’    process.env.POSTGRES_PRISMA_URL ??
 44вҶ’    process.env.POSTGRES_URL_NON_POOLING ??
 45вҶ’    null
 46вҶ’  );
 47вҶ’}
 48вҶ’
 49вҶ’function resolveSslConfig(connectionString: string): PoolConfig["ssl"] | undefined {
 50вҶ’  if (process.env.POSTGRES_SSL_NO_VERIFY === "true") {
 51вҶ’    return { rejectUnauthorized: false };
 52вҶ’  }
 53вҶ’
 54вҶ’  try {
 55вҶ’    const parsed = new URL(connectionString);
 56вҶ’    const sslMode = parsed.searchParams.get("sslmode")?.trim().toLowerCase();
 57вҶ’    if (sslMode === "no-verify") {
 58вҶ’      return { rejectUnauthorized: false };
 59вҶ’    }
 60вҶ’  } catch {
 61вҶ’    // Ignore URL parsing issues and let pg handle connection string validation.
 62вҶ’  }
 63вҶ’
 64вҶ’  return undefined;
 65вҶ’}
 66вҶ’
 67вҶ’function applyNoVerifySslMode(connectionString: string): string {
 68вҶ’  try {
 69вҶ’    const parsed = new URL(connectionString);
 70вҶ’    parsed.searchParams.set("sslmode", "no-verify");
 71вҶ’    parsed.searchParams.delete("sslrootcert");
 72вҶ’    return parsed.toString();
 73вҶ’  } catch {
 74вҶ’    return connectionString;
 75вҶ’  }
 76вҶ’}
 77вҶ’
 78вҶ’function classifyDatabaseError(error: unknown): Error {
 79вҶ’  if (error instanceof StorageUnavailableError) return error;
 80вҶ’  if (!(error instanceof Error)) {
 81вҶ’    return new StorageUnavailableError("Storage temporarily unavailable", { cause: error });
 82вҶ’  }
 83вҶ’
 84вҶ’  const anyError = error as Error & { code?: string };
 85вҶ’  const code = typeof anyError.code === "string" ? anyError.code : "";
 86вҶ’  const message = error.message.toLowerCase();
 87вҶ’
 88вҶ’  if (NETWORK_ERROR_CODES.has(code) || message.includes("timeout") || message.includes("failed to fetch")) {
 89вҶ’    return new StorageUnavailableError("Storage temporarily unavailable", { cause: error });
 90вҶ’  }
 91вҶ’
 92вҶ’  return error;
 93вҶ’}
 94вҶ’
 95вҶ’function withTimeout<T>(promise: Promise<T>, timeoutMs: number): Promise<T> {
 96вҶ’  return new Promise<T>((resolve, reject) => {
 97вҶ’    const timeout = setTimeout(() => {
 98вҶ’      reject(new StorageUnavailableError(`Database query timed out after ${timeoutMs}ms`));
 99вҶ’    }, timeoutMs);
100вҶ’
101вҶ’    promise
102вҶ’      .then((value) => {
103вҶ’        clearTimeout(timeout);
104вҶ’        resolve(value);
105вҶ’      })
106вҶ’      .catch((error) => {
107вҶ’        clearTimeout(timeout);
108вҶ’        reject(error);
109вҶ’      });
110вҶ’  });
111вҶ’}
