113вҶ’export function getPool(): Pool {
114вҶ’  if (pool) return pool;
115вҶ’
116вҶ’  const connectionString = resolveConnectionString();
117вҶ’  if (!connectionString) {
118вҶ’    throw new StorageUnavailableError("POSTGRES_URL is not configured");
119вҶ’  }
120вҶ’
121вҶ’  const max = Number(process.env.POSTGRES_POOL_MAX ?? "5") || 5;
122вҶ’  const normalizedConnectionString =
123вҶ’    process.env.POSTGRES_SSL_NO_VERIFY === "true" ? applyNoVerifySslMode(connectionString) : connectionString;
124вҶ’  const ssl = resolveSslConfig(normalizedConnectionString);
125вҶ’
126вҶ’  pool = new Pool({
127вҶ’    connectionString: normalizedConnectionString,
128вҶ’    max,
129вҶ’    ssl,
130вҶ’  });
131вҶ’
132вҶ’  pool.on("error", (error) => {
133вҶ’    console.error("Postgres pool error", error);
134вҶ’  });
135вҶ’
136вҶ’  return pool;
137вҶ’}
