139вҶ’export async function query<T = unknown>(text: string, values: unknown[] = []): Promise<QueryResult<T>> {
140вҶ’  try {
141вҶ’    const db = getPool();
142вҶ’    return await withTimeout(db.query<T>(text, values), DEFAULT_QUERY_TIMEOUT_MS);
143вҶ’  } catch (error) {
144вҶ’    throw classifyDatabaseError(error);
145вҶ’  }
146вҶ’}
