 28вҶ’export function computeMovingAverage(
 29вҶ’  values: number[],
 30вҶ’  windowSize: number,
 31вҶ’): number | null {
 32вҶ’  if (values.length === 0) return null;
 33вҶ’  const window = values.slice(-windowSize);
 34вҶ’  return window.reduce((a, b) => a + b, 0) / window.length;
 35вҶ’}
