 37вҶ’export function computeZScore(
 38вҶ’  value: number,
 39вҶ’  historicalValues: number[],
 40вҶ’): number | null {
 41вҶ’  if (historicalValues.length < 3) return null;
 42вҶ’  const mean =
 43вҶ’    historicalValues.reduce((a, b) => a + b, 0) / historicalValues.length;
 44вҶ’  const variance =
 45вҶ’    historicalValues.reduce((sum, v) => sum + (v - mean) ** 2, 0) /
 46вҶ’    historicalValues.length;
 47вҶ’  const stddev = Math.sqrt(variance);
 48вҶ’  if (stddev === 0) return 0;
 49вҶ’  return (value - mean) / stddev;
 50вҶ’}
