 52вҶ’export function detectAnomalies(
 53вҶ’  value: number,
 54вҶ’  history: number[],
 55вҶ’  metricName: string,
 56вҶ’  threshold = 2,
 57вҶ’): AnomalyFlag | null {
 58вҶ’  const z = computeZScore(value, history);
 59вҶ’  if (z === null || Math.abs(z) <= threshold) return null;
 60вҶ’  return {
 61вҶ’    metric: metricName,
 62вҶ’    zScore: Math.round(z * 100) / 100,
 63вҶ’    direction: z > 0 ? "increase" : "decrease",
 64вҶ’  };
 65вҶ’}
