 69вҶ’interface DeltaRow {
 70вҶ’  snapshotDate: string;
 71вҶ’  baselineSnapshotDate: string;
 72вҶ’  verticalId: string;
 73вҶ’  pointId: string;
 74вҶ’  deltaType: DeltaType;
 75вҶ’  deltaField: string | null;
 76вҶ’  previousValue: string | null;
 77вҶ’  currentValue: string | null;
 78вҶ’  deltaMagnitude: number | null;
 79вҶ’  deltaDirection: DeltaDirection;
 80вҶ’  deltaSummary: string | null;
 81вҶ’}
