 83вҶ’function detectChangedFields(
 84вҶ’  current: Record<string, unknown>,
 85вҶ’  previous: Record<string, unknown>,
 86вҶ’): Array<{
 87вҶ’  field: string;
 88вҶ’  prev: string;
 89вҶ’  curr: string;
 90вҶ’  magnitude: number | null;
 91вҶ’  direction: DeltaDirection;
 92вҶ’}> {
 93вҶ’  const changes: Array<{
 94вҶ’    field: string;
 95вҶ’    prev: string;
 96вҶ’    curr: string;
 97вҶ’    magnitude: number | null;
 98вҶ’    direction: DeltaDirection;
 99вҶ’  }> = [];
100вҶ’
101вҶ’  const allKeys = new Set([...Object.keys(current), ...Object.keys(previous)]);
102вҶ’  for (const key of allKeys) {
103вҶ’    if (SKIP_FIELDS.has(key)) continue;
104вҶ’    const cv = current[key];
105вҶ’    const pv = previous[key];
106вҶ’    const cs = JSON.stringify(cv ?? null);
107вҶ’    const ps = JSON.stringify(pv ?? null);
108вҶ’    if (cs === ps) continue;
109вҶ’
110вҶ’    let magnitude: number | null = null;
111вҶ’    let direction: DeltaDirection = "not_applicable";
112вҶ’    if (typeof cv === "number" && typeof pv === "number") {
113вҶ’      magnitude = cv - pv;
114вҶ’      direction = cv > pv ? "increase" : cv < pv ? "decrease" : "stable";
115вҶ’    }
116вҶ’
117вҶ’    changes.push({
118вҶ’      field: key,
119вҶ’      prev: ps,
120вҶ’      curr: cs,
121вҶ’      magnitude,
122вҶ’      direction,
123вҶ’    });
124вҶ’  }
125вҶ’  return changes;
126вҶ’}
