128вҶ’export function computeDeltas(
129вҶ’  currentMap: Map<string, ProjectedPoint>,
130вҶ’  previousMap: Map<string, ProjectedPoint>,
131вҶ’  snapshotDate: string,
132вҶ’  baselineDate: string,
133вҶ’): DeltaRow[] {
134вҶ’  const deltas: DeltaRow[] = [];
135вҶ’
136вҶ’  // New points
137вҶ’  for (const [pointId, point] of currentMap) {
138вҶ’    if (!previousMap.has(pointId)) {
139вҶ’      deltas.push({
140вҶ’        snapshotDate,
141вҶ’        baselineSnapshotDate: baselineDate,
142вҶ’        verticalId: point.category,
143вҶ’        pointId,
144вҶ’        deltaType: "new",
145вҶ’        deltaField: null,
146вҶ’        previousValue: null,
147вҶ’        currentValue: null,
148вҶ’        deltaMagnitude: null,
149вҶ’        deltaDirection: "not_applicable",
150вҶ’        deltaSummary: `New ${point.category} point added`,
151вҶ’      });
152вҶ’    }
153вҶ’  }
154вҶ’
155вҶ’  // Removed points
156вҶ’  for (const [pointId, point] of previousMap) {
157вҶ’    if (!currentMap.has(pointId)) {
158вҶ’      deltas.push({
159вҶ’        snapshotDate,
160вҶ’        baselineSnapshotDate: baselineDate,
161вҶ’        verticalId: point.category,
162вҶ’        pointId,
163вҶ’        deltaType: "removed",
164вҶ’        deltaField: null,
165вҶ’        previousValue: null,
166вҶ’        currentValue: null,
167вҶ’        deltaMagnitude: null,
168вҶ’        deltaDirection: "not_applicable",
169вҶ’        deltaSummary: `${point.category} point removed`,
170вҶ’      });
171вҶ’    }
172вҶ’  }
173вҶ’
174вҶ’  // Changed / unchanged
175вҶ’  for (const [pointId, current] of currentMap) {
176вҶ’    const previous = previousMap.get(pointId);
177вҶ’    if (!previous) continue;
178вҶ’
179вҶ’    const changes = detectChangedFields(
180вҶ’      current.details as Record<string, unknown>,
181вҶ’      previous.details as Record<string, unknown>,
182вҶ’    );
183вҶ’
184вҶ’    if (changes.length === 0) {
185вҶ’      deltas.push({
186вҶ’        snapshotDate,
187вҶ’        baselineSnapshotDate: baselineDate,
188вҶ’        verticalId: current.category,
189вҶ’        pointId,
190вҶ’        deltaType: "unchanged",
191вҶ’        deltaField: null,
192вҶ’        previousValue: null,
193вҶ’        currentValue: null,
194вҶ’        deltaMagnitude: null,
195вҶ’        deltaDirection: "stable",
196вҶ’        deltaSummary: null,
197вҶ’      });
198вҶ’    } else {
199вҶ’      for (const change of changes) {
200вҶ’        const pctStr =
201вҶ’          change.magnitude !== null && change.direction !== "not_applicable"
202вҶ’            ? ` (${change.direction === "increase" ? "+" : ""}${change.magnitude})`
203вҶ’            : "";
204вҶ’        deltas.push({
205вҶ’          snapshotDate,
206вҶ’          baselineSnapshotDate: baselineDate,
207вҶ’          verticalId: current.category,
208вҶ’          pointId,
209вҶ’          deltaType: "changed",
210вҶ’          deltaField: change.field,
211вҶ’          previousValue: change.prev,
212вҶ’          currentValue: change.curr,
213вҶ’          deltaMagnitude: change.magnitude,
214вҶ’          deltaDirection: change.direction,
215вҶ’          deltaSummary: `${change.field} changed: ${change.prev} вҶ’ ${change.curr}${pctStr}`,
216вҶ’        });
217вҶ’      }
218вҶ’    }
219вҶ’  }
220вҶ’
221вҶ’  return deltas;
222вҶ’}
