476вҶ’export interface SnapshotResult {
477вҶ’  snapshotDate: string;
478вҶ’  snapshotsInserted: number;
479вҶ’  deltasInserted: number;
480вҶ’  statsComputed: number;
481вҶ’  baselineDate: string | null;
482вҶ’}
483вҶ’
484вҶ’export async function runWeeklySnapshot(
485вҶ’  dateOverride?: string,
486вҶ’): Promise<SnapshotResult> {
487вҶ’  const snapshotDate =
488вҶ’    dateOverride ?? new Date().toISOString().slice(0, 10);
489вҶ’
490вҶ’  // Step 1: build current projection
491вҶ’  const [pointEvents, legacySubs] = await Promise.all([
492вҶ’    getPointEvents(),
493вҶ’    getLegacySubmissions(),
494вҶ’  ]);
495вҶ’  const allEvents = mergePointEventsWithLegacy(pointEvents, legacySubs);
496вҶ’  const projectedPoints = projectPointsFromEvents(allEvents);
497вҶ’
498вҶ’  // Step 2: build snapshot rows
499вҶ’  const snapshotRows = buildSnapshotRows(snapshotDate, projectedPoints);
500вҶ’
501вҶ’  // Step 3: insert snapshots
502вҶ’  const snapshotsInserted = await insertSnapshotRows(snapshotRows);
503вҶ’
504вҶ’  // Step 4: compute deltas
505вҶ’  const baselineDate = await getPreviousSnapshotDate(snapshotDate);
506вҶ’  let deltasInserted = 0;
507вҶ’
508вҶ’  const currentMap = new Map<string, ProjectedPoint>();
509вҶ’  for (const p of projectedPoints) currentMap.set(p.pointId, p);
510вҶ’
511вҶ’  let deltasByVertical = new Map<string, { new: number; removed: number; changed: number; unchanged: number }>();
512вҶ’
513вҶ’  if (baselineDate) {
514вҶ’    const previousMap = await loadSnapshotAsMap(baselineDate);
515вҶ’    const deltas = computeDeltas(
516вҶ’      currentMap,
517вҶ’      previousMap,
518вҶ’      snapshotDate,
519вҶ’      baselineDate,
520вҶ’    );
521вҶ’    deltasInserted = await insertDeltaRows(deltas);
522вҶ’
523вҶ’    // Aggregate delta counts by vertical
524вҶ’    for (const d of deltas) {
525вҶ’      const counts = deltasByVertical.get(d.verticalId) ?? {
526вҶ’        new: 0,
527вҶ’        removed: 0,
528вҶ’        changed: 0,
529вҶ’        unchanged: 0,
530вҶ’      };
531вҶ’      if (d.deltaType === "new") counts.new++;
532вҶ’      else if (d.deltaType === "removed") counts.removed++;
533вҶ’      else if (d.deltaType === "changed") counts.changed++;
534вҶ’      else if (d.deltaType === "unchanged") counts.unchanged++;
535вҶ’      deltasByVertical.set(d.verticalId, counts);
536вҶ’    }
537вҶ’  }
538вҶ’
539вҶ’  // Step 5: compute stats per vertical
540вҶ’  const verticalGroups = new Map<string, ProjectedPoint[]>();
541вҶ’  for (const p of projectedPoints) {
542вҶ’    const list = verticalGroups.get(p.category) ?? [];
543вҶ’    list.push(p);
544вҶ’    verticalGroups.set(p.category, list);
545вҶ’  }
546вҶ’
547вҶ’  // Also include verticals with 0 current points but deltas (removed points)
548вҶ’  for (const vid of deltasByVertical.keys()) {
549вҶ’    if (!verticalGroups.has(vid)) verticalGroups.set(vid, []);
550вҶ’  }
551вҶ’
552вҶ’  let statsComputed = 0;
553вҶ’
554вҶ’  for (const [verticalId, points] of verticalGroups) {
555вҶ’    const totalPoints = points.length;
556вҶ’    const completedPoints = points.filter((p) => p.gaps.length === 0).length;
557вҶ’    const completionRate =
558вҶ’      totalPoints > 0
559вҶ’        ? Math.round((completedPoints / totalPoints) * 10000) / 100
560вҶ’        : 0;
561вҶ’
562вҶ’    const dc = deltasByVertical.get(verticalId) ?? {
563вҶ’      new: 0,
564вҶ’      removed: 0,
565вҶ’      changed: 0,
566вҶ’      unchanged: 0,
567вҶ’    };
568вҶ’
569вҶ’    // Average price for fuel verticals
570вҶ’    let avgPrice: number | null = null;
571вҶ’    if (verticalId === "fuel_station") {
572вҶ’      const prices = points
573вҶ’        .map((p) => p.details.fuelPrice)
574вҶ’        .filter((v): v is number => typeof v === "number" && v > 0);
575вҶ’      if (prices.length > 0) {
576вҶ’        avgPrice =
577вҶ’          Math.round(
578вҶ’            (prices.reduce((a, b) => a + b, 0) / prices.length) * 100,
579вҶ’          ) / 100;
580вҶ’      }
581вҶ’    }
582вҶ’
583вҶ’    // Historical data for trends
584вҶ’    const history = await getHistoricalStats(verticalId, snapshotDate, 8);
585вҶ’    const histTotalPoints = history.map((h) => h.total_points);
586вҶ’    const histNewCount = history.map((h) => h.new_count);
587вҶ’    const histRemovedCount = history.map((h) => h.removed_count);
588вҶ’
589вҶ’    // Week-over-week growth
590вҶ’    let weekOverWeekGrowth: number | null = null;
591вҶ’    if (history.length > 0 && history[0].total_points > 0) {
592вҶ’      weekOverWeekGrowth =
593вҶ’        Math.round(
594вҶ’          ((totalPoints - history[0].total_points) /
595вҶ’            history[0].total_points) *
596вҶ’            10000,
597вҶ’        ) / 100;
598вҶ’    }
599вҶ’
600вҶ’    // Moving average (4-week)
601вҶ’    const movingAvg4w = computeMovingAverage(
602вҶ’      [...histTotalPoints.reverse(), totalPoints],
603вҶ’      4,
604вҶ’    );
605вҶ’
606вҶ’    // Z-scores
607вҶ’    const zScoreTotalPoints = computeZScore(totalPoints, histTotalPoints);
608вҶ’    const zScoreNewCount = computeZScore(dc.new, histNewCount);
609вҶ’    const zScoreRemovedCount = computeZScore(dc.removed, histRemovedCount);
610вҶ’
611вҶ’    // Anomaly detection
612вҶ’    const anomalyFlags: AnomalyFlag[] = [];
613вҶ’    const a1 = detectAnomalies(totalPoints, histTotalPoints, "total_points");
614вҶ’    if (a1) anomalyFlags.push(a1);
615вҶ’    const a2 = detectAnomalies(dc.new, histNewCount, "new_count");
616вҶ’    if (a2) anomalyFlags.push(a2);
617вҶ’    const a3 = detectAnomalies(dc.removed, histRemovedCount, "removed_count");
618вҶ’    if (a3) anomalyFlags.push(a3);
619вҶ’
620вҶ’    await upsertStatsRow({
621вҶ’      snapshotDate,
622вҶ’      verticalId,
623вҶ’      totalPoints,
624вҶ’      completedPoints,
625вҶ’      completionRate,
626вҶ’      newCount: dc.new,
627вҶ’      removedCount: dc.removed,
628вҶ’      changedCount: dc.changed,
629вҶ’      unchangedCount: dc.unchanged,
630вҶ’      avgPrice,
631вҶ’      weekOverWeekGrowth,
632вҶ’      movingAvg4w: movingAvg4w !== null ? Math.round(movingAvg4w * 100) / 100 : null,
633вҶ’      zScoreTotalPoints: zScoreTotalPoints !== null ? Math.round(zScoreTotalPoints * 100) / 100 : null,
634вҶ’      zScoreNewCount: zScoreNewCount !== null ? Math.round(zScoreNewCount * 100) / 100 : null,
635вҶ’      zScoreRemovedCount: zScoreRemovedCount !== null ? Math.round(zScoreRemovedCount * 100) / 100 : null,
636вҶ’      anomalyFlags,
637вҶ’    });
638вҶ’    statsComputed++;
639вҶ’  }
640вҶ’
641вҶ’  return {
642вҶ’    snapshotDate,
643вҶ’    snapshotsInserted,
644вҶ’    deltasInserted,
645вҶ’    statsComputed,
646вҶ’    baselineDate,
647вҶ’  };
648вҶ’}
