 12вҶ’function trimString(input: unknown): string | undefined {
 13вҶ’  if (typeof input !== "string") return undefined;
 14вҶ’  const trimmed = input.trim();
 15вҶ’  return trimmed || undefined;
 16вҶ’}
 17вҶ’
 18вҶ’function hasValue(input: unknown): boolean {
 19вҶ’  if (typeof input === "string") return Boolean(input.trim());
 20вҶ’  if (typeof input === "number") return Number.isFinite(input);
 21вҶ’  if (typeof input === "boolean") return true;
 22вҶ’  if (Array.isArray(input)) return input.length > 0;
 23вҶ’  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 24вҶ’  return false;
 25вҶ’}
 26вҶ’
 27вҶ’function normalizeDetailsForCategory(category: SubmissionCategory, raw: SubmissionDetails): SubmissionDetails {
 28вҶ’  return getVertical(category).normalizeDetails(raw);
 29вҶ’}
 30вҶ’
 31вҶ’function mergeDetails(base: SubmissionDetails, incoming: SubmissionDetails): SubmissionDetails {
 32вҶ’  const merged: SubmissionDetails = { ...base };
 33вҶ’  const entries = Object.entries(incoming) as Array<[string, unknown]>;
 34вҶ’  for (const [key, value] of entries) {
 35вҶ’    if (!hasValue(value)) continue;
 36вҶ’    if (Array.isArray(value)) {
 37вҶ’      merged[key] = value;
 38вҶ’      continue;
 39вҶ’    }
 40вҶ’    if (typeof value === "object" && value !== null && !Array.isArray(value)) {
 41вҶ’      const prev = merged[key];
 42вҶ’      if (typeof prev === "object" && prev !== null && !Array.isArray(prev)) {
 43вҶ’        merged[key] = { ...(prev as Record<string, unknown>), ...(value as Record<string, unknown>) };
 44вҶ’      } else {
 45вҶ’        merged[key] = value;
 46вҶ’      }
 47вҶ’      continue;
 48вҶ’    }
 49вҶ’    merged[key] = value;
 50вҶ’  }
 51вҶ’  return merged;
 52вҶ’}
