 54вҶ’export function listMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
 55вҶ’  const normalized = normalizeDetailsForCategory(category, details);
 56вҶ’  return getVertical(category).enrichableFields.filter((field) => !hasValue(normalized[field]));
 57вҶ’}
