 64вҶ’export function isEnrichFieldAllowed(category: SubmissionCategory, field: string): boolean {
 65вҶ’  const canonicalField =
 66вҶ’    field === "merchantId"
 67вҶ’      ? "merchantIdByProvider"
 68вҶ’      : field === "hasCashAvailable"
 69вҶ’        ? "hasMin50000XafAvailable"
 70вҶ’      : field === "hours"
 71вҶ’        ? "openingHours"
 72вҶ’        : field === "isOnCall" || field === "onDuty"
 73вҶ’          ? "isOnDuty"
 74вҶ’          : field;
 75вҶ’  return getVertical(category).enrichableFields.includes(canonicalField);
 76вҶ’}
