 98вҶ’export function projectPointsFromEvents(events: PointEvent[]): ProjectedPoint[] {
 99вҶ’  const groups = new Map<string, ProjectedPoint>();
100вҶ’  const sorted = [...events].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
101вҶ’  for (const event of sorted) {
102вҶ’    const normalizedDetails = normalizeDetailsForCategory(event.category, event.details ?? {});
103вҶ’    const existing = groups.get(event.pointId);
104вҶ’    if (!existing) {
105вҶ’      groups.set(
106вҶ’        event.pointId,
107вҶ’        {
108вҶ’          id: event.pointId,
109вҶ’          pointId: event.pointId,
110вҶ’          category: event.category,
111вҶ’          location: event.location,
112вҶ’          details: normalizedDetails,
113вҶ’          photoUrl: event.photoUrl,
114вҶ’          createdAt: event.createdAt,
115вҶ’          updatedAt: event.createdAt,
116вҶ’          source: event.source,
117вҶ’          externalId: event.externalId,
118вҶ’          gaps: listMissingFields(event.category, normalizedDetails),
119вҶ’          eventsCount: 1,
120вҶ’          eventIds: [event.id],
121вҶ’        },
122вҶ’      );
123вҶ’      continue;
124вҶ’    }
125вҶ’
126вҶ’    existing.category = event.category;
127вҶ’    existing.location = event.location ?? existing.location;
128вҶ’    existing.details = mergeDetails(existing.details, normalizedDetails);
129вҶ’    existing.updatedAt = event.createdAt;
130вҶ’    existing.eventsCount += 1;
131вҶ’    existing.eventIds.push(event.id);
132вҶ’    if (event.photoUrl) existing.photoUrl = event.photoUrl;
133вҶ’    if (event.source) existing.source = event.source;
134вҶ’    if (event.externalId) existing.externalId = event.externalId;
135вҶ’    existing.gaps = listMissingFields(existing.category, existing.details);
136вҶ’  }
137вҶ’
138вҶ’  return Array.from(groups.values()).sort(
139вҶ’    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
140вҶ’  );
141вҶ’}
