167вҶ’export function mergePointEventsWithLegacy(pointEvents: PointEvent[], legacySubmissions: LegacySubmission[]): PointEvent[] {
168вҶ’  const merged = [...pointEvents];
169вҶ’  const seen = new Set(merged.map((item) => item.id));
170вҶ’  for (const legacy of legacySubmissions) {
171вҶ’    const converted = legacySubmissionToCreateEvent(legacy);
172вҶ’    if (seen.has(converted.id)) continue;
173вҶ’    merged.push(converted);
174вҶ’    seen.add(converted.id);
175вҶ’  }
176вҶ’  return merged;
177вҶ’}
