 3вҶ’export function buildUrl(path: string) {
 4вҶ’  if (!API_BASE) return path;
 5вҶ’  return `${API_BASE}${path.startsWith("/") ? path : `/${path}`}`;
 6вҶ’}
 7вҶ’
 8вҶ’export async function apiFetch(path: string, init: RequestInit = {}) {
 9вҶ’  return fetch(buildUrl(path), {
10вҶ’    credentials: "include",
11вҶ’    ...init,
12вҶ’    headers: {
13вҶ’      ...(init.headers ?? {}),
14вҶ’    },
15вҶ’  });
16вҶ’}
