18вҶ’export async function apiJson<T>(path: string, init: RequestInit = {}): Promise<T> {
19вҶ’  const response = await apiFetch(path, init);
20вҶ’  if (!response.ok) {
21вҶ’    const text = await response.text();
22вҶ’    throw new Error(text || "Request failed");
23вҶ’  }
24вҶ’  return (await response.json()) as T;
25вҶ’}
