 3вҶ’
 4вҶ’export function getAuthSecret(): string | null {
 5вҶ’  return process.env.AUTH_SECRET ?? process.env.NEXTAUTH_SECRET ?? null;
 6вҶ’}
 7вҶ’
 8вҶ’export function isSecureRequest(): boolean {
 9вҶ’  const authUrl = process.env.AUTH_URL ?? process.env.NEXTAUTH_URL ?? "";
10вҶ’  if (typeof authUrl === "string" && authUrl.startsWith("https://")) return true;
11вҶ’  return process.env.NODE_ENV === "production";
12вҶ’}
