14вҶ’export function getSessionCookieName(): string {
15вҶ’  return isSecureRequest() ? "__Secure-authjs.session-token" : "authjs.session-token";
16вҶ’}
17вҶ’
18вҶ’export async function getAuthToken(request: Request): Promise<JWT | null> {
19вҶ’  const secret = getAuthSecret();
20вҶ’  if (!secret) return null;
21вҶ’  const cookieName = getSessionCookieName();
22вҶ’  const secureCookie = isSecureRequest();
23вҶ’  const salt = cookieName;
24вҶ’  const authHeader = request.headers.get("authorization");
25вҶ’  if (authHeader?.toLowerCase().startsWith("bearer ")) {
26вҶ’    const raw = authHeader.slice(7).trim();
27вҶ’    const decoded = await decode({ token: raw, secret, salt });
28вҶ’    return decoded ?? null;
29вҶ’  }
30вҶ’  return await getToken({ req: request, secret, salt, cookieName, secureCookie });
31вҶ’}
