33вҶ’export async function requireUser(request: Request): Promise<{ id: string; token: JWT } | null> {
34вҶ’  const token = await getAuthToken(request);
35вҶ’  if (!token) return null;
36вҶ’  const email = typeof token.email === "string" ? token.email.toLowerCase().trim() : null;
37вҶ’  const uid = (token as JWT & { uid?: unknown }).uid;
38вҶ’  const normalizedUid = typeof uid === "string" ? uid.trim() : null;
39вҶ’  const sub = typeof token.sub === "string" ? token.sub.trim() : null;
40вҶ’  const id = email || normalizedUid || sub;
41вҶ’  if (!id) return null;
42вҶ’  return { id, token };
