262вҶ’  const fetchRows = async (includePhone: boolean): Promise<UserProfile[]> => {
263вҶ’    const cols = includePhone
264вҶ’      ? "id, email, phone, name, image, occupation, xp, password_hash, is_admin, map_scope"
265вҶ’      : "id, email, name, image, occupation, xp, password_hash, is_admin, map_scope";
266вҶ’    const result = await query<Record<string, unknown>>(
267вҶ’      `select ${cols} from user_profiles where id = ANY($1::text[])`,
268вҶ’      [normalizedIds],
269вҶ’    );
270вҶ’    return result.rows.map(rowToUserProfile);
271вҶ’  };
272вҶ’
273вҶ’  let rows: UserProfile[];
274вҶ’  if (phoneColumnState === "missing") {
275вҶ’    rows = await fetchRows(false);
276вҶ’  } else {
277вҶ’    try {
278вҶ’      rows = await fetchRows(true);
279вҶ’      if (phoneColumnState === "unknown") phoneColumnState = "present";
