302вҶ’async function insertPointEvent(event: PointEvent): Promise<void> {
303вҶ’  const id = normalizeEventId(event.id);
304вҶ’  const pointId = typeof event.pointId === "string" && event.pointId.trim() ? event.pointId.trim() : id;
305вҶ’  const eventType = parseEventType(event.eventType);
306вҶ’  const userId = normalizeUserId(event.userId || "unknown");
307вҶ’  const category = parseCategory(event.category);
308вҶ’  const location = parseLocation(event.location);
309вҶ’  if (!location) throw new Error("Invalid point event location");
310вҶ’  const details = event.details && typeof event.details === "object" ? event.details : {};
311вҶ’  const photoUrl = typeof event.photoUrl === "string" ? event.photoUrl : null;
312вҶ’  const createdAt = normalizeCreatedAt(event.createdAt);
313вҶ’  const source = typeof event.source === "string" ? event.source : null;
314вҶ’  const externalId = typeof event.externalId === "string" ? event.externalId : null;
315вҶ’
316вҶ’  await query(
317вҶ’    `
